<template>
  <div class="app_main">
    <keep-alive>
      <router-view v-if="$route.meta.keepAlive"></router-view>
    </keep-alive>
    <router-view v-if="!$route.meta.keepAlive" :key="key"></router-view>
  </div>
</template>
<script>
export default {
  computed: {
    key() {
      return this.$route.path;
    }
  }
};
</script>
<style scoped lang='scss'>
.app_main {
  width: 100%;
  height: calc(100% - 9vh);
}
</style>
